+	report, err := receivePack(ctx, session, repo.Storer, req, hashesToPush, !targetAdv.Capabilities.Supports(capability.OFSDelta))
+	if err != nil {
+		return err
+	}
+	if report != nil {
+		if err := report.Error(); err != nil {
+			return err
+		}
+	}
+	return nil
